+
+        // /anything/else -> wildcard catch-all
+        let m = router.match_path("/anything/else", Method::Get).unwrap();
+        assert_eq!(m.route.path, "/{*path}");
+        assert_eq!(m.params[0], ("path", "anything/else"));
+    }
